import{_ as t,c as s,o as a,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Update Skills: Sync with Source Repository | OpenSkills","description":"Learn OpenSkills update command to refresh skills. Support batch update, specific skill update, local and git repository updates, and troubleshoot failures.","frontmatter":{"title":"Update Skills: Sync with Source Repository | OpenSkills","sidebarTitle":"Update Skills","subtitle":"Update Skills: Keep Skills Synced with Source Repository","description":"Learn OpenSkills update command to refresh skills. Support batch update, specific skill update, local and git repository updates, and troubleshoot failures.","tags":["skills","update","git"],"prerequisite":["start-installation","start-first-skill"],"order":5},"headers":[],"relativePath":"numman-ali/openskills/platforms/update-skills/index.md","filePath":"numman-ali/openskills/platforms/update-skills/index.md"}'),i={name:"numman-ali/openskills/platforms/update-skills/index.md"};function o(n,e,d,r,p,c){return a(),s("div",null,[...e[0]||(e[0]=[l(`<h1 id="update-skills-keep-skills-synced-with-source-repository" tabindex="-1">Update Skills: Keep Skills Synced with Source Repository <a class="header-anchor" href="#update-skills-keep-skills-synced-with-source-repository" aria-label="Permalink to &quot;Update Skills: Keep Skills Synced with Source Repository&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>This lesson teaches you how to keep OpenSkills skills always at the latest version. Using the OpenSkills update command, you will be able to:</p><ul><li>Update all installed skills with one command</li><li>Update only specific skills</li><li>Understand update differences for different installation sources</li><li>Troubleshoot update failures</li></ul><h2 id="your-current-challenges" tabindex="-1">Your Current Challenges <a class="header-anchor" href="#your-current-challenges" aria-label="Permalink to &quot;Your Current Challenges&quot;">​</a></h2><p>Skill repositories are constantly updating—authors may fix bugs, add new features, or improve documentation. But your installed skills are still at the old version.</p><p>You may have encountered these situations:</p><ul><li>The skill documentation says &quot;supports feature X&quot;, but your AI agent says it doesn&#39;t know</li><li>The skill has better error messages, but you still see the old ones</li><li>A bug fixed after installation still affects you</li></ul><p><strong>Deleting and reinstalling every time is too cumbersome</strong>—you need an efficient way to update.</p><h2 id="when-to-use-this-command" tabindex="-1">When to Use This Command <a class="header-anchor" href="#when-to-use-this-command" aria-label="Permalink to &quot;When to Use This Command&quot;">​</a></h2><p>Typical scenarios for using the <code>update</code> command:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Action</th></tr></thead><tbody><tr><td>Discover skill has updates</td><td>Run <code>openskills update</code></td></tr><tr><td>Update only a few skills</td><td><code>openskills update skill1,skill2</code></td></tr><tr><td>Test locally developed skills</td><td>Update from local path</td></tr><tr><td>Update from GitHub repository</td><td>Automatically git clone latest code</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Update Frequency Recommendations</p><ul><li><strong>Community skills</strong>: Update once a month to get latest improvements</li><li><strong>Self-developed skills</strong>: Manually update after each modification</li><li><strong>Local path skills</strong>: Update after each code change</li></ul></div><h2 id="🎒-before-you-start" tabindex="-1">🎒 Before You Start <a class="header-anchor" href="#🎒-before-you-start" aria-label="Permalink to &quot;🎒 Before You Start&quot;">​</a></h2><p>Before beginning, confirm you have completed:</p><ul><li>[x] Installed OpenSkills (see <a href="./../../start/installation/">Install OpenSkills</a>)</li><li>[x] Installed at least one skill (see <a href="./../../start/first-skill/">Install Your First Skill</a>)</li><li>[x] Have network connection if installed from GitHub</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>OpenSkills update mechanism is simple:</p><p><strong>Record source information during installation → Re-copy from original source during update</strong></p><div class="info custom-block"><p class="custom-block-title">Why Re-installation Is Needed</p><p>Older versions of skills (installed without source information) cannot be updated. In this case, you need to reinstall once. OpenSkills will remember the source, and after that, automatic updates are possible.</p></div><p><strong>Update methods for three installation sources</strong>:</p><table tabindex="0"><thead><tr><th>Source Type</th><th>Update Method</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Local path</strong></td><td>Copy directly from local path</td><td>Develop your own skills</td></tr><tr><td><strong>git repository</strong></td><td>Clone latest code to temp directory</td><td>Install from GitHub/GitLab</td></tr><tr><td><strong>GitHub shorthand</strong></td><td>Convert to full URL then clone</td><td>Install from GitHub official repository</td></tr></tbody></table><p>During update, skills without source metadata will be skipped, and names of skills that need reinstallation will be listed.</p><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-list-installed-skills" tabindex="-1">Step 1: List Installed Skills <a class="header-anchor" href="#step-1-list-installed-skills" aria-label="Permalink to &quot;Step 1: List Installed Skills&quot;">​</a></h3><p>First confirm which skills are available for update:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>What You Should See</strong>: A list of installed skills, including name, description, and installation location label (project/global)</p><h3 id="step-2-update-all-skills" tabindex="-1">Step 2: Update All Skills <a class="header-anchor" href="#step-2-update-all-skills" aria-label="Permalink to &quot;Step 2: Update All Skills&quot;">​</a></h3><p>The simplest way is to update all installed skills:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>What You Should See</strong>: Skills updated one by one, each showing update result</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Skipped: my-old-skill (no source metadata; re-install once to enable updates)</span></span>
<span class="line"><span>Summary: 2 updated, 1 skipped (3 total)</span></span></code></pre></div><details class="details custom-block"><summary>Meaning of Skipped Skills</summary><p>If you see <code>Skipped: xxx (no source metadata)</code>, it means this skill was installed before the update feature was added. You need to reinstall it once to enable automatic updates.</p></details><h3 id="step-3-update-specific-skills" tabindex="-1">Step 3: Update Specific Skills <a class="header-anchor" href="#step-3-update-specific-skills" aria-label="Permalink to &quot;Step 3: Update Specific Skills&quot;">​</a></h3><p>If you only want to update specific skills, pass skill names (comma-separated):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git-workflow,check-branch-first</span></span></code></pre></div><p><strong>What You Should See</strong>: Only the two specified skills are updated</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Summary: 2 updated, 0 skipped (2 total)</span></span></code></pre></div><h3 id="step-4-update-locally-developed-skills" tabindex="-1">Step 4: Update Locally Developed Skills <a class="header-anchor" href="#step-4-update-locally-developed-skills" aria-label="Permalink to &quot;Step 4: Update Locally Developed Skills&quot;">​</a></h3><p>If you&#39;re developing skills locally, you can update from the local path:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill</span></span></code></pre></div><p><strong>What You Should See</strong>: The skill is re-copied from the local path where you installed it</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: my-skill</span></span>
<span class="line"><span>Summary: 1 updated, 0 skipped (1 total)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Local Development Workflow</p><p>Development process:</p><ol><li>Install skill: <code>openskills install ./my-skill</code></li><li>Modify code</li><li>Update skill: <code>openskills update my-skill</code></li><li>Sync to AGENTS.md: <code>openskills sync</code></li></ol></div><h3 id="step-5-handle-update-failures" tabindex="-1">Step 5: Handle Update Failures <a class="header-anchor" href="#step-5-handle-update-failures" aria-label="Permalink to &quot;Step 5: Handle Update Failures&quot;">​</a></h3><p>If some skills fail to update, OpenSkills will display detailed reasons:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>Possible situations you might see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skipped: git-workflow (git clone failed)</span></span>
<span class="line"><span>Skipped: my-skill (local source missing)</span></span>
<span class="line"><span>Missing source metadata (1): old-skill</span></span>
<span class="line"><span>Clone failed (1): git-workflow</span></span></code></pre></div><p><strong>Corresponding solutions</strong>:</p><table tabindex="0"><thead><tr><th>Error Message</th><th>Cause</th><th>Solution</th></tr></thead><tbody><tr><td><code>no source metadata</code></td><td>Old version installation</td><td>Reinstall: <code>openskills install &lt;source&gt;</code></td></tr><tr><td><code>local source missing</code></td><td>Local path deleted</td><td>Restore local path or reinstall</td></tr><tr><td><code>SKILL.md missing at local source</code></td><td>Local files deleted</td><td>Restore SKILL.md file</td></tr><tr><td><code>git clone failed</code></td><td>Network issue or repository doesn&#39;t exist</td><td>Check network or repository URL</td></tr><tr><td><code>SKILL.md not found in repo</code></td><td>Repository structure changed</td><td>Contact skill author or update subpath</td></tr></tbody></table><h2 id="checklist-✅" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅" aria-label="Permalink to &quot;Checklist ✅&quot;">​</a></h2><p>Confirm you have learned:</p><ul><li>[ ] Can use <code>openskills update</code> to update all skills</li><li>[ ] Can use comma-separated names to update specific skills</li><li>[ ] Understand meaning of &quot;skipped&quot; skills and solutions</li><li>[ ] Know the update workflow for locally developed skills</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="❌-common-mistakes" tabindex="-1">❌ Common Mistakes <a class="header-anchor" href="#❌-common-mistakes" aria-label="Permalink to &quot;❌ Common Mistakes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mistake</th><th>Correct Approach</th></tr></thead><tbody><tr><td>Ignore skipped skills</td><td>Reinstall or fix issues based on prompts</td></tr><tr><td>Delete and reinstall every time</td><td>Using <code>update</code> command is more efficient</td></tr><tr><td>Don&#39;t know where skill was installed from</td><td>Use <code>openskills list</code> to check source</td></tr></tbody></table><h3 id="⚠️-important-notes" tabindex="-1">⚠️ Important Notes <a class="header-anchor" href="#⚠️-important-notes" aria-label="Permalink to &quot;⚠️ Important Notes&quot;">​</a></h3><p><strong>Update Overwrites Local Modifications</strong></p><p>If you directly modified skill files in the installation directory, these modifications will be overwritten during update. The correct approach is:</p><ol><li>Modify <strong>source files</strong> (local path or repository)</li><li>Then run <code>openskills update</code></li></ol><p><strong>Symlink Skills Need Special Handling</strong></p><p>If skills are installed via symbolic links (see <a href="./../../advanced/symlink-support/">Symlink Support</a>), updates will recreate the links without breaking the symlink relationship.</p><p><strong>Global and Project Skills Need Separate Updates</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Only update project skills (default)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Global skills need separate handling</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or use --universal mode for unified management</span></span></code></pre></div><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>In this lesson, you learned OpenSkills update functionality:</p><ul><li><strong>Batch update</strong>: <code>openskills update</code> updates all skills with one command</li><li><strong>Specific update</strong>: <code>openskills update skill1,skill2</code> updates specific skills</li><li><strong>Source awareness</strong>: Automatically recognizes local paths and git repositories</li><li><strong>Error messages</strong>: Detailed explanations of skip reasons and solutions</li></ul><p>The update feature keeps skills at the latest version, ensuring the skills you use always contain the latest improvements and fixes.</p><h2 id="up-next" tabindex="-1">Up Next <a class="header-anchor" href="#up-next" aria-label="Permalink to &quot;Up Next&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../remove-skills/">Remove Skills</a></strong>.</p><p>You will learn:</p><ul><li>How to use the interactive <code>manage</code> command to remove skills</li><li>How to use the <code>remove</code> command for scripted removal</li><li>Considerations after removing skills</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Update skills main logic</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L14-L150" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>14-150</td></tr><tr><td>Local path update</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L64-L82" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>64-82</td></tr><tr><td>Git repository update</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L85-L125" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>85-125</td></tr><tr><td>Copy skill from directory</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L152-L163" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>152-163</td></tr><tr><td>Path safety validation</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L165-L172" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>165-172</td></tr><tr><td>Metadata structure definition</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L8-L15" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>8-15</td></tr><tr><td>Read skill metadata</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L17-L27" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>17-27</td></tr><tr><td>Write skill metadata</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L29-L36" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>29-36</td></tr><tr><td>CLI command definition</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/cli.ts#L58-L62" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>58-62</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>SKILL_METADATA_FILE = &#39;.openskills.json&#39;</code>: Metadata file name, records skill installation source</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>updateSkills(skillNames)</code>: Main function to update specified or all skills</li><li><code>updateSkillFromDir(targetPath, sourceDir)</code>: Copy skill from source directory to target directory</li><li><code>isPathInside(targetPath, targetDir)</code>: Validate installation path safety (prevent path traversal)</li><li><code>readSkillMetadata(skillDir)</code>: Read skill metadata</li><li><code>writeSkillMetadata(skillDir, metadata)</code>: Write/update skill metadata</li></ul><p><strong>Business Rules</strong>:</p><ul><li><strong>BR-5-1</strong>: Default update all installed skills (update.ts:37-38)</li><li><strong>BR-5-2</strong>: Support comma-separated skill name list (update.ts:15)</li><li><strong>BR-5-3</strong>: Skip skills without source metadata (update.ts:56-62)</li><li><strong>BR-5-4</strong>: Support local path updates (update.ts:64-82)</li><li><strong>BR-5-5</strong>: Support updates from git repositories (update.ts:85-125)</li><li><strong>BR-5-6</strong>: Validate path safety (update.ts:156-162)</li></ul></details>`,75)])])}const k=t(i,[["render",o]]);export{u as __pageData,k as default};
